        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Grid-stride over rows
        for (uint32_t row = blockIdx; row < batchSize_; row += blockDim_) {
            uint32_t rowStart = row * dim_;

            // ---- Pass 1: compute max over the row (vector reduction) ----
            float maxVal = -1e38f;   // small enough
            uint32_t remaining = dim_;
            uint32_t offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                LoadTile(rowStart + offset, curLen);
                AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
                float tileMax = AscendC::ReduceMax(xLocal, curLen);
                if (tileMax > maxVal) maxVal = tileMax;
                inQueueX_.FreeTensor(xLocal);
                remaining -= curLen;
                offset += curLen;
            }

            // ---- Pass 2: compute sum of exp(x - maxVal) (vector exp + reduction) ----
            float sum = 0.0f;
            remaining = dim_;
            offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                LoadTile(rowStart + offset, curLen);
                AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();
                AscendC::Sub(tmp, xLocal, maxVal, curLen);          // tmp = x - maxVal
                AscendC::Exp(tmp, tmp, curLen);                     // tmp = exp(x - maxVal)
                float tileSum = AscendC::ReduceAdd(tmp, curLen);
                sum += tileSum;
                tmpQueue_.FreeTensor(tmp);
                inQueueX_.FreeTensor(xLocal);
                remaining -= curLen;
                offset += curLen;
            }

            // ---- scalar logSum via AscendC Log on a 1-element tensor ----
            AscendC::LocalTensor<float> logTensor = tmpQueue_.AllocTensor<float>();
            logTensor.SetValue(0, sum);
            AscendC::Log(logTensor, logTensor, 1);
            float logSum = logTensor.GetValue(0);
            tmpQueue_.FreeTensor(logTensor);

            float offsetVal = maxVal + logSum;   // = log(sum(exp(x - max))) + max

            // ---- Pass 3: compute output y = x - offsetVal (vector) ----
            remaining = dim_;
            offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                LoadTile(rowStart + offset, curLen);
                AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
                AscendC::Sub(yLocal, xLocal, offsetVal, curLen);    // y = x - offsetVal
                inQueueX_.FreeTensor(xLocal);
                outQueueY_.EnQue<float>(yLocal);
                StoreTile(rowStart + offset, curLen);
                remaining -= curLen;
                offset += curLen;
            }
        }
